import{_ as p,c as e}from"./app.0b00aae6.js";const o={},r=e('<h1 id="_18-\u8BB2-\u773C\u524D\u4E00\u4EAE-\u5E26\u4F60\u73A9\u8F6C-gui-\u81EA\u52A8\u5316\u7684\u6D4B\u8BD5\u62A5\u544A" tabindex="-1"><a class="header-anchor" href="#_18-\u8BB2-\u773C\u524D\u4E00\u4EAE-\u5E26\u4F60\u73A9\u8F6C-gui-\u81EA\u52A8\u5316\u7684\u6D4B\u8BD5\u62A5\u544A" aria-hidden="true">#</a> 18 \u8BB2\uFF1A\u773C\u524D\u4E00\u4EAE\uFF1A\u5E26\u4F60\u73A9\u8F6C GUI \u81EA\u52A8\u5316\u7684\u6D4B\u8BD5\u62A5\u544A</h1><p>\u5728 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7CFB\u5217\u7684\u6587\u7AE0\u4E2D\uFF0C\u6211\u56F4\u7ED5\u7740 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8FDB\u884C\u4E86\u5404\u79CD\u8BA8\u8BBA\uFF1A\u4ECE\u6700\u539F\u59CB\u7684 GUI \u6D4B\u8BD5\u8C08\u8D77\uFF0C\u9010\u6E10\u5F15\u5165\u4E86\u811A\u672C\u4E0E\u6570\u636E\u7684\u89E3\u8026\uFF0C\u5E76\u8C08\u8BBA\u4E86\u9875\u9762\u5BF9\u8C61\u6A21\u578B\uFF0C\u4EE5\u53CA\u5728\u6B64\u57FA\u7840\u4E0A\u7684\u4E1A\u52A1\u6D41\u7A0B\u6A21\u578B\uFF0C\u63A5\u7740\u5206\u4EAB\u4E86\u4E00\u4E9B GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u7684\u65B0\u6280\u672F\uFF0C\u6700\u540E\u548C\u4F60\u8BA8\u8BBA\u4E86 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u7A33\u5B9A\u6027\u95EE\u9898\u3002</p><p>\u4ECA\u5929\uFF0C\u6211\u4F1A\u518D\u548C\u4F60\u804A\u804A GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u53E6\u5916\u4E00\u4E2A\u5F88\u5B9E\u7528\u7684\u90E8\u5206\uFF1AGUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u62A5\u544A\u3002</p><p>GUI \u6D4B\u8BD5\u62A5\u544A\u662F GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u91CD\u8981\u7EC4\u6210\u90E8\u5206\uFF0C\u5F53\u6709\u4EFB\u4F55\u7684\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u5931\u8D25\u65F6\uFF0C\u6211\u4EEC\u9996\u5148\u5C31\u4F1A\u53BB\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\uFF0C\u5E0C\u671B\u4ECE\u4E2D\u770B\u5230\u6D4B\u8BD5\u7528\u4F8B\u5230\u5E95\u662F\u5728\u54EA\u4E00\u6B65\u51FA\u9519\u4E86\uFF0C\u9519\u8BEF\u53D1\u751F\u65F6\u88AB\u6D4B\u7CFB\u7EDF\u662F\u5728\u54EA\u4E2A\u9875\u9762\u4E0A\uFF0C\u5E76\u4E14\u524D\u5E8F\u6B65\u9AA4\u53C8\u662F\u54EA\u4E9B\u9875\u9762\u7B49\u7B49\u3002</p><p><strong>\u65E9\u671F\u7684\u57FA\u4E8E\u89C6\u9891\u7684 GUI \u6D4B\u8BD5\u62A5\u544A</strong></p><p>\u4E3A\u4E86\u5206\u6790\u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u8FC7\u7A0B\u4E0E\u7ED3\u679C\uFF0C\u65E9\u671F\u5C31\u51FA\u73B0\u4E86\u57FA\u4E8E\u89C6\u9891\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0CGUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u4F1A\u5BF9\u6D4B\u8BD5\u6267\u884C\u6574\u4E2A\u8FC7\u7A0B\u8FDB\u884C\u5C4F\u5E55\u5F55\u50CF\u5E76\u751F\u6210\u89C6\u9891\u3002</p><p>\u8FD9\u79CD\u57FA\u4E8E\u89C6\u9891\u7684\u6D4B\u8BD5\u62A5\u544A\u53EF\u4EE5\u63D0\u4F9B\u6E05\u6670\u7684 GUI \u6D4B\u8BD5\u6267\u884C\u4E0A\u4E0B\u6587\uFF0C\u770B\u8D77\u6765\u4E5F\u5F88\u4E0D\u9519\u3002\u4F46\u662F\uFF0C\u8FD9\u79CD\u65B9\u5F0F\u4E3B\u8981\u7684\u95EE\u9898\u662F\uFF1A</p><p>\u62A5\u544A\u7684\u4F53\u79EF\u901A\u5E38\u90FD\u6BD4\u8F83\u5927\uFF0C\u5C0F\u7684\u51E0 MB\uFF0C\u5927\u7684\u4E0A\u767E MB\uFF0C\u8FD9\u5BF9\u6D4B\u8BD5\u62A5\u544A\u7684\u7BA1\u7406\u548C\u5B9E\u65F6\u4F20\u8F93\u975E\u5E38\u4E0D\u5229\u3002</p><p>\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u65F6\uFF0C\u5F80\u5F80\u9700\u8981\u7ED3\u5408\u6D4B\u8BD5\u7528\u4F8B\u4EE5\u53CA\u670D\u52A1\u7AEF\u7684\u65E5\u5FD7\u4FE1\u606F\uFF0C\u89C6\u9891\u62A5\u544A\u8FD9\u4E00\u70B9\u4E0A\u4E5F\u6709\u6240\u6B20\u7F3A\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u7406\u60F3\u4E2D\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u5E94\u8BE5\u662F\u7531\u4E00\u7CFB\u5217\u6309\u65F6\u95F4\u987A\u5E8F\u6392\u5217\u7684\u5C4F\u5E55\u622A\u56FE\u7EC4\u6210\uFF0C\u5E76\u4E14\u8FD9\u4E9B\u622A\u56FE\u4E0A\u53EF\u4EE5\u9AD8\u4EAE\u663E\u793A\u6240\u64CD\u4F5C\u7684\u5143\u7D20\uFF0C\u540C\u65F6\u6309\u7167\u6267\u884C\u987A\u5E8F\u914D\u6709\u76F8\u5173\u64CD\u4F5C\u6B65\u9AA4\u7684\u8BE6\u7EC6\u63CF\u8FF0</strong>\u3002</p><p>\u4F46\u662F\uFF0C\u65E9\u671F\u7684\u5546\u4E1A GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8F6F\u4EF6\u4E5F\u53EA\u662F\u5177\u5907\u6700\u57FA\u672C\u7684\u987A\u5E8F\u622A\u56FE\uFF0C\u5E76\u4E0D\u5177\u5907\u9AD8\u4EAE\u6240\u64CD\u4F5C\u5143\u7D20\u7684\u529F\u80FD\uFF0C\u540E\u6765\u5546\u7528\u5DE5\u5177\u5382\u5546\u6839\u636E\u7528\u6237\u7684\u5B9E\u9645\u4F7F\u7528\u53CD\u9988\uFF0C\u9010\u6E10\u5B8C\u5584\u548C\u6539\u8FDB\u3002</p><p>\u76EE\u524D\uFF0C\u5546\u4E1A\u7684 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8F6F\u4EF6\uFF0C\u6BD4\u5982\u4F7F\u7528\u6700\u4E3A\u5E7F\u6CDB\u7684 UFT\uFF08\u5C31\u662F\u4EE5\u524D\u7684 QTP\uFF09\uFF0C\u5DF2\u7ECF\u81EA\u5E26\u4E86\u622A\u56FE\u4EE5\u53CA\u9AD8\u4EAE\u663E\u793A\u64CD\u4F5C\u5143\u7D20\u529F\u80FD\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u4F7F\u7528 UFT \u6267\u884C\u4E00\u4E2A GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u4F60\u65E0\u9700\u505A\u4EFB\u4F55\u989D\u5916\u7684\u5DE5\u4F5C\uFF0C\u5C31\u80FD\u5F97\u5230\u4E00\u4EFD\u6BD4\u8F83\u7406\u60F3\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u3002</p><p><strong>\u5F00\u6E90 GUI \u6D4B\u8BD5\u6846\u67B6\u7684\u6D4B\u8BD5\u62A5\u544A\u5B9E\u73B0\u601D\u8DEF</strong></p><p>\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u4F7F\u7528\u7684\u662F\u5F00\u6E90\u8F6F\u4EF6\uFF0C\u6BD4\u5982 Selenium WebDriver\uFF0C\u90A3\u5C31\u9700\u8981\u81EA\u5DF1\u53BB\u5B9E\u73B0\u622A\u56FE\u4EE5\u53CA\u9AD8\u4EAE\u663E\u793A\u64CD\u4F5C\u5143\u7D20\u7684\u529F\u80FD\u3002\u5B9E\u73B0\u7684\u601D\u8DEF\u901A\u5E38\u662F\uFF1A</p><p>\u5229\u7528 Selenium WebDriver \u7684 screenshot \u51FD\u6570\u5728\u4E00\u4E9B\u7279\u5B9A\u7684\u65F6\u673A\uFF08\u6BD4\u5982\uFF0C\u9875\u9762\u53D1\u751F\u8DF3\u8F6C\u65F6\uFF0C\u5728\u9875\u9762\u4E0A\u64CD\u4F5C\u67D0\u4E2A\u63A7\u4EF6\u65F6\uFF0C\u6216\u8005\u662F\u6D4B\u8BD5\u5931\u8D25\u65F6\uFF0C\u7B49\u7B49\uFF09\u5B8C\u6210\u754C\u9762\u622A\u56FE\u529F\u80FD\u3002</p><p>\u5177\u4F53\u5230\u4EE3\u7801\u5B9E\u73B0\uFF0C\u901A\u5E38\u6709\u4E24\u79CD\u65B9\u5F0F\uFF1A</p><ol><li>\u6269\u5C55 Selenium \u539F\u672C\u7684\u64CD\u4F5C\u51FD\u6570\uFF1B</li><li>\u5728\u76F8\u5173\u7684 Hook \u64CD\u4F5C\u4E2D\u8C03\u7528 screenshot \u51FD\u6570\u3002</li></ol><p>\u4E0B\u9762\uFF0C\u6211\u4F1A\u5206\u522B\u9488\u5BF9\u8FD9\u4E24\u4E2A\u5B9E\u73B0\u65B9\u5F0F\uFF0C\u7ED9\u51FA\u5177\u4F53\u7684\u793A\u4F8B\uFF0C\u5E2E\u4F60\u7406\u89E3\u5E76\u5B9E\u73B0\u8FD9\u4E2A\u529F\u80FD\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u6269\u5C55 Selenium \u539F\u672C\u7684\u64CD\u4F5C\u51FD\u6570\u5B9E\u73B0\u622A\u56FE\u4EE5\u53CA\u9AD8\u4EAE\u663E\u793A\u64CD\u4F5C\u5143\u7D20\u7684\u529F\u80FD</strong></p><p>\u65E2\u7136 Selenium \u539F\u751F\u7684 click \u64CD\u4F5C\u51FD\u6570\u5E76\u4E0D\u5177\u5907\u622A\u56FE\u4EE5\u53CA\u9AD8\u4EAE\u663E\u793A\u64CD\u4F5C\u5143\u7D20\u7684\u529F\u80FD\uFF0C\u90A3\u6211\u4EEC\u5C31\u6765\u5B9E\u73B0\u4E00\u4E2A\u81EA\u5DF1 click \u51FD\u6570\u3002</p><p>\u5F53\u81EA\u5DF1\u5B9E\u73B0\u7684 click \u51FD\u6570\u88AB\u8C03\u7528\u65F6\uFF1A</p><ol><li>\u9996\u5148\uFF0C\u7528 Javascript \u4EE3\u7801\u9AD8\u4EAE\u663E\u793A\u88AB\u64CD\u4F5C\u7684\u5143\u7D20\uFF0C\u9AD8\u4EAE\u7684\u5B9E\u73B0\u65B9\u5F0F\u5C31\u662F\u5229\u7528 JavaScript \u5728\u5BF9\u8C61\u7684\u8FB9\u6846\u4E0A\u6E32\u67D3\u4E00\u4E2A 5-8 \u4E2A\u50CF\u7D20\u7684\u8FB9\u7F18\uFF1B</li><li>\u7136\u540E\uFF0C\u8C03\u7528 screenshot \u51FD\u6570\u5B8C\u6210\u70B9\u51FB\u524D\u7684\u622A\u56FE\uFF1B</li><li>\u6700\u540E\uFF0C\u8C03\u7528 Selenium \u539F\u751F\u7684 click \u51FD\u6570\u5B8C\u6210\u771F\u6B63\u7684\u70B9\u51FB\u64CD\u4F5C\u3002</li></ol><p>\u90A3\u4E48\uFF0C\u4EE5\u540E\u51E1\u662F\u9700\u8981\u8C03\u7528 click \u51FD\u6570\u65F6\uFF0C\u90FD\u76F4\u63A5\u8C03\u7528\u8FD9\u4E2A\u81EA\u5DF1\u5C01\u88C5\u7684 click \u51FD\u6570\uFF0C\u76F4\u63A5\u5F97\u5230\u9AD8\u4EAE\u4E86\u88AB\u64CD\u4F5C\u5BF9\u8C61\u7684\u754C\u9762\u622A\u56FE\u3002</p><p>\u5982\u56FE 1 \u6240\u793A\uFF0C\u5C31\u662F\u7528\u8FD9\u79CD\u65B9\u5F0F\u4EA7\u751F\u7684\u754C\u9762\u622A\u56FE\uFF0C\u56FE\u4E2D\u4F9D\u6B21\u663E\u793A\u4E86\u767B\u5F55\u8FC7\u7A0B\u4E2D\u6BCF\u4E00\u4E2A\u64CD\u4F5C\u7684\u63A7\u4EF6\uFF0C\u7B2C\u4E00\u5F20\u9AD8\u4EAE\u4E86\u201CUsername\u201D\u7684\u8F93\u5165\u6846\uFF0C\u56E0\u4E3A\u81EA\u52A8\u5316\u4EE3\u7801\u4F1A\u5728\u201CUsername\u201D\u6846\u4E2D\u8F93\u5165\u7528\u6237\u540D\uFF1B\u7B2C\u4E8C\u5F20\u9AD8\u4EAE\u4E86\u201CPassword\u201D\u7684\u8F93\u5165\u6846\uFF0C\u56E0\u4E3A\u81EA\u52A8\u5316\u4EE3\u7801\u4F1A\u5728\u201CPassword\u201D\u6846\u4E2D\u8F93\u5165\u5BC6\u7801\uFF1B\u7B2C\u4E09\u5F20\u9AD8\u4EAE\u4E86\u201DSign in\u201C\u6309\u94AE\uFF0C\u56E0\u4E3A\u81EA\u52A8\u5316\u4EE3\u7801\u4F1A\u53BB\u70B9\u51FB\u8FD9\u4E2A\u6309\u94AE\u3002 <img src="https://static001.geekbang.org/resource/image/cd/67/cd6e86a73dc2a13c285f0c94dbe2e367.png" alt="GUI\u754C\u9762\u7684\u65F6\u95F4\u987A\u5E8F\u622A\u56FE\u793A\u4F8B"></p><p><strong>\u7B2C\u4E8C\uFF0C\u5728\u76F8\u5173\u7684 Hook \u64CD\u4F5C\u4E2D\u8C03\u7528 screenshot \u51FD\u6570\u5B9E\u73B0\u622A\u56FE\u4EE5\u53CA\u9AD8\u4EAE\u663E\u793A\u64CD\u4F5C\u5143\u7D20\u7684\u529F\u80FD</strong></p><p>\u5176\u5B9E\u4F7F\u7528 Hook \u7684\u65B9\u6CD5\u6BD4\u8F83\u7B80\u5355\u548C\u76F4\u89C2\uFF0C\u4F46\u662F\u4F60\u9996\u5148\u8981\u7406\u89E3\u4EC0\u4E48\u662F Hook\u3002</p><p>Hook \u4E2D\u6587\u7684\u610F\u601D\u662F\u201C\u94A9\u5B50\u201D\uFF0C\u76F4\u63A5\u901A\u8FC7\u5B9A\u4E49\u4ECB\u7ECD\u4EC0\u4E48\u662F\u201C\u94A9\u5B50\u201D\u4F1A\u6709\u4E9B\u96BE\u4EE5\u7406\u89E3\uFF0C\u90A3\u4E48\u6211\u5C31\u901A\u8FC7\u4E00\u4E2A\u5B9E\u4F8B\u6765\u8DDF\u4F60\u89E3\u91CA\u4E00\u4E0B\u3002</p><p>\u5F53\u6267\u884C\u67D0\u4E2A\u51FD\u6570 F \u65F6\uFF0C\u7CFB\u7EDF\u4F1A\u5728\u6267\u884C\u51FD\u6570 F \u524D\u5148\u9690\u5F0F\u6267\u884C\u4E00\u4E2A\u7A7A\u5B9E\u73B0\u7684\u51FD\u6570\uFF0C\u90A3\u4E48\u5F53\u4F60\u9700\u8981\u505A\u4E00\u4E9B\u6269\u5C55\u6216\u8005\u62E6\u622A\u65F6\uFF0C\u5C31\u53EF\u4EE5\u5728\u8FD9\u4E2A\u7A7A\u5B9E\u73B0\u7684\u51FD\u6570\u4E2D\u52A0\u5165\u81EA\u5B9A\u4E49\u7684\u64CD\u4F5C\u4E86\u3002\u90A3\u4E48\u8FD9\u4E2A\u7A7A\u5B9E\u73B0\u7684\u51FD\u6570\u5C31\u662F\u6240\u8C13\u7684 Hook \u51FD\u6570\u3002</p><p>\u8FD9\u6837\u7684\u4F8B\u5B50\u6709\u5F88\u591A\uFF0C\u6BD4\u5982 Java \u7684 main \u51FD\u6570\uFF0C\u7CFB\u7EDF\u5728\u6267\u884C main \u51FD\u6570\u4E4B\u524D\u4F1A\u5148\u5728\u540E\u53F0\u9690\u5F0F\u6267\u884C premain \u51FD\u6570\uFF1BJUnit \u548C TestNG\uFF0C\u90FD\u6709\u6240\u8C13\u7684 BeforeTest \u548C AfterTest \u65B9\u6CD5\uFF0C\u8FD9\u4E9B\u90FD\u662F\u53EF\u4EE5\u5728\u7279\u5B9A\u6B65\u9AA4\u7684\u524D\u540E\u63D2\u5165\u81EA\u5B9A\u4E49\u64CD\u4F5C\u7684\u63A5\u53E3\u3002</p><p>\u8BF4\u5230\u8FD9\u91CC\uFF0C\u4F60\u53EF\u80FD\u5DF2\u7ECF\u77E5\u9053\u8981\u600E\u4E48\u505A\u4E86\uFF1A\u6211\u53EF\u4EE5\u5728\u8FD9\u4E9B Hook \u51FD\u6570\u4E2D\u6DFB\u52A0\u622A\u56FE\u3001\u5143\u7D20\u9AD8\u4EAE\uFF0C\u4EE5\u53CA\u989D\u5916\u7684\u4EFB\u610F\u64CD\u4F5C\uFF0C\u6BD4\u5982\u66F4\u591A\u7684\u8BE6\u7EC6\u65E5\u5FD7\u8F93\u51FA\u7B49\u7B49\u3002</p><p>\u53E6\u5916\uFF0C\u6211\u5728\u524D\u9762\u7684\u6587\u7AE0\u4E2D\u5206\u4EAB\u4E86\u57FA\u4E8E\u4E1A\u52A1\u6D41\u7A0B\u7684\u811A\u672C\u5C01\u88C5\uFF0C\u4F60\u53EF\u4EE5\u518D\u601D\u8003\u4E00\u4E0B\uFF0C\u5982\u4F55\u5728 GUI \u62A5\u544A\u4E2D\u4F53\u73B0\u51FA\u4E1A\u52A1\u6D41\u7A0B\u7684\u6982\u5FF5\uFF0C\u8FD9\u6837\u7684\u6D4B\u8BD5\u62A5\u544A\u4F1A\u5177\u6709\u66F4\u597D\u7684\u53EF\u8BFB\u6027\u3002</p><p>\u6BD4\u5982\uFF0C\u56FE 2 \u6240\u793A\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u5C31\u663E\u793A\u4E86\u5177\u4F53\u7684 Flow \u540D\u79F0\u3002\u8FD9\u4E2A\u529F\u80FD\uFF0C\u5C31\u662F\u901A\u8FC7 Hook \u51FD\u6570\u5B9E\u73B0\u7684\u3002</p><p>\u5177\u4F53\u7684\u5B9E\u73B0\u903B\u8F91\u4E5F\u6BD4\u8F83\u7B80\u5355\u7684\uFF0C\u5C31\u662F\u5728 Flow \u5F00\u59CB\u7684\u7B2C\u4E00\u4E2A Hook \u51FD\u6570\u4E2D\u8C03\u7528\u589E\u52A0\u62A5\u544A\u9875\u7684\u51FD\u6570\uFF0C\u5E76\u5728\u8FD9\u4E2A\u65B0\u589E\u7684\u62A5\u544A\u9875\u4E2D\u8F93\u51FA Flow \u7684\u540D\u5B57\u3002 <img src="https://static001.geekbang.org/resource/image/f3/81/f335cb50728cb59ba1597697271d0081.png" alt="\u5728GUI\u6D4B\u8BD5\u62A5\u544A\u4E2D\u4F53\u73B0\u4E1A\u52A1\u6D41\u7A0B"></p><p>\u4E0A\u9762\u6240\u8BB2\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u90FD\u662F\u9488\u5BF9\u4E00\u4E2A\u56FD\u5BB6\u7684\uFF0C\u5F53\u9762\u5BF9\u591A\u4E2A\u56FD\u5BB6\u7AD9\u70B9\u7684 GUI \u6D4B\u8BD5\u65F6\uFF0C\u4E8B\u60C5\u5C31\u4F1A\u53D8\u5F97\u66F4\u52A0\u590D\u6742\uFF0C\u4F60\u5C31\u5FC5\u987B\u53BB\u8003\u8651\u5168\u7403\u5316 GUI \u6D4B\u8BD5\u62A5\u544A\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1\u3002</p><p><strong>\u5168\u7403\u5316 GUI \u6D4B\u8BD5\u62A5\u544A\u7684\u521B\u65B0\u8BBE\u8BA1</strong></p><p>\u6240\u8C13\u5168\u7403\u5316\u6D4B\u8BD5\u662F\u6307\uFF0C\u540C\u4E00\u4E2A\u4E1A\u52A1\u5728\u5168\u7403\u5404\u4E2A\u56FD\u5BB6\u90FD\u6709\u81EA\u5DF1\u7F51\u7AD9\u3002\u6BD4\u5982\uFF0C\u4E00\u4E9B\u5927\u578B\u5168\u7403\u5316\u7535\u5546\u4F01\u4E1A\u5728\u5F88\u591A\u56FD\u5BB6\u90FD\u6709\u81EA\u5DF1\u7684\u7AD9\u70B9\uFF0C\u90A3\u4E48\u5BF9\u8FD9\u4E9B\u7AD9\u70B9\u7684\u6D4B\u8BD5\u9664\u4E86\u8981\u5173\u6CE8\u57FA\u672C\u7684\u529F\u80FD\uFF0C\u4EE5\u53CA\u5404\u4E2A\u56FD\u5BB6\u7279\u6709\u7684\u529F\u80FD\u5916\uFF0C\u8FD8\u8981\u53BB\u9A8C\u8BC1\u754C\u9762\u5E03\u5C40\u4EE5\u53CA\u7FFB\u8BD1\u5728\u4E0A\u4E0B\u6587\u73AF\u5883\u4E2D\u662F\u5426\u5408\u9002\u3002</p><p>\u65E9\u671F\u7684\u505A\u6CD5\u662F\uFF0C\u96C7\u4F63\u5F53\u5730\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u7531\u4ED6\u4EEC\u624B\u5DE5\u6267\u884C\u4E3B\u8981\u7684\u4E1A\u52A1\u573A\u666F\u6D4B\u8BD5\uFF0C\u5E76\u9A8C\u8BC1\u76F8\u5173\u7684\u9875\u9762\u5E03\u5C40\uFF0C\u4EE5\u53CA\u7FFB\u8BD1\u5185\u5BB9\u4E0E\u4E0A\u4E0B\u6587\u4E2D\u7684\u5339\u914D\u5EA6\u3002\u5728\u5F53\u5730\u4E13\u95E8\u96C7\u4F63\u7684\u8FD9\u4E9B\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u88AB\u79F0\u4E3A LQA\u3002</p><p>\u663E\u7136\uFF0C\u8058\u8BF7 LQA \u7684\u6548\u7387\u975E\u5E38\u4F4E\uFF0C\u4E3B\u8981\u539F\u56E0\u662F\uFF1A\u5168\u90E8\u6D4B\u8BD5\u5DE5\u4F5C\u90FD\u7531 LQA \u5728\u9879\u76EE\u540E\u671F\u624B\u5DE5\u6267\u884C\uFF0C\u6267\u884C\u524D\u8FD8\u9700\u8981\u5BF9\u4ED6\u4EEC\u8FDB\u884C\u4E1A\u52A1\u57F9\u8BAD\uFF1B\u540C\u65F6\uFF0C\u6211\u4EEC\u9700\u8981\u51C6\u5907\u975E\u5E38\u8BE6\u5C3D\u7684\u6D4B\u8BD5\u7528\u4F8B\u6587\u6863\uFF0CLQA \u4E5F\u8981\u82B1\u5F88\u5927\u7684\u7CBE\u529B\u53BB\u622A\u56FE\u5E76\u5B8C\u6210\u6700\u7EC8\u7684\u6D4B\u8BD5\u62A5\u544A\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u79CD\u4F4E\u6548\u7684\u6A21\u5F0F\uFF0C\u6700\u597D\u7684\u89E3\u51B3\u65B9\u6CD5\u5C31\u662F\uFF1A\u5229\u7528 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u751F\u6210\u5B8C\u6574\u7684\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u7684\u622A\u56FE\u3002\u8FD9\u6837\uFF0CLQA \u5C31\u4E0D\u518D\u9700\u8981\u53BB\u624B\u5DE5\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u4E86\uFF0C\u800C\u662F\u76F4\u63A5\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u4E2D\u4E1A\u52A1\u64CD\u4F5C\u8FC7\u7A0B\u4E2D GUI \u754C\u9762\u622A\u56FE\u5C31\u53EF\u4EE5\u4E86\uFF0C\u7136\u540E\u53D1\u73B0\u9875\u9762\u5E03\u5C40\u95EE\u9898\u6216\u8005\u662F\u4E0D\u6070\u5F53\u7684\u7FFB\u8BD1\u95EE\u9898\u3002</p><p>\u8FD9\u4E2A\u65B9\u6848\u770B\u8D77\u6765\u5DF2\u7ECF\u6BD4\u8F83\u5B8C\u7F8E\u4E86\uFF0CLQA \u7684\u5DE5\u4F5C\u91CD\u70B9\u4E5F\u66F4\u6E05\u6670\u4E86\uFF0C\u4F46\u8FD9\u5E76\u4E0D\u662F\u6700\u4F18\u7684\u65B9\u6848\u3002\u56E0\u4E3A\u8FD9\u4E9B LQA \u5728\u5B9E\u9645\u5DE5\u4F5C\u4E2D\uFF0C\u8FD8\u4F1A\u6709\u4EE5\u4E0B\u4E09\u4E2A\u6BD4\u8F83\u75DB\u82E6\u7684\u5730\u65B9\uFF1A</p><ol><li>\u9700\u8981\u7ECF\u5E38\u5728\u591A\u4E2A\u56FD\u5BB6\u7684\u6D4B\u8BD5\u62A5\u544A\u4E4B\u95F4\u6765\u56DE\u5207\u6362\u53BB\u6BD4\u8F83\u9875\u9762\u5E03\u5C40\uFF1B</li><li>\u9700\u8981\u9891\u7E41\u5207\u6362\u5230\u7F8E\u56FD\u7F51\u7AD9\uFF08\u4E5F\u5C31\u662F\u4E3B\u7AD9\uFF09\u7684\u62A5\u544A\uFF0C\u53BB\u6BD4\u8F83\u7FFB\u8BD1\u5185\u5BB9\u4E0E\u4E0A\u4E0B\u6587\u7684\u5339\u914D\u5EA6\uFF1B</li><li>\u53D1\u73B0\u7F3A\u9677\u540E\uFF0C\u8FD8\u662F\u9700\u8981\u4ECE GUI \u6D4B\u8BD5\u62A5\u544A\u4E2D\u590D\u5236\u622A\u56FE\uFF0C\u5E76\u7528\u56FE\u50CF\u8F6F\u4EF6\u6807\u6CE8\u6709\u95EE\u9898\u7684\u70B9\uFF0C\u7136\u540E\u624D\u80FD\u6253\u5F00\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\u9012\u4EA4\u7F3A\u9677\u62A5\u544A\u3002</li></ol><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E09\u4E2A\u95EE\u9898\uFF0C\u6211\u5EFA\u8BAE\u4F60\u5EFA\u7ACB\u4EE5\u4E0B\u5F62\u5F0F\u7684\u6D4B\u8BD5\u62A5\u544A\u3002\u8FD9\u91CC\u6709\u4E00\u5F20\u56FE\u7247\u5C55\u793A\u4E86\u4E00\u4EFD\u5305\u542B\u591A\u56FD\u8BED\u8A00\u6BD4\u8F83\u62A5\u544A\u7684\u793A\u4F8B\uFF0C\u542C\u97F3\u9891\u7684\u7528\u6237\u53EF\u4EE5\u70B9\u51FB\u6587\u7A3F\u67E5\u770B\u5982\u56FE 3 \u6240\u793A\u3002 <img src="https://static001.geekbang.org/resource/image/39/19/393c6ae5fe669e5513da9a2f7588af19.png" alt="\u591A\u56FD\u8BED\u8A00\u6BD4\u8F83\u62A5\u544A"></p><p>\u62A5\u544A\u7684\u6A2A\u5411\uFF0C\u662F\u4E00\u4E2A\u56FD\u5BB6\u7684\u4E1A\u52A1\u6D4B\u8BD5\u987A\u5E8F\u622A\u56FE\uFF0C\u6BD4\u5982\u56FE\u4E2D\u7B2C\u4E00\u884C\u662F\u82F1\u56FD\u7F51\u7AD9\u7684\u767B\u5F55\u4E1A\u52A1\u6D41\u7A0B\u987A\u5E8F\u622A\u56FE\uFF0C\u7B2C\u4E8C\u884C\u662F\u5FB7\u56FD\u7F51\u7AD9\u7684\u767B\u5F55\u4E1A\u52A1\u6D41\u7A0B\u987A\u5E8F\u622A\u56FE\u3002\u62A5\u544A\u7684\u7EB5\u5411\uFF0C\u5C55\u793A\u7684\u81EA\u7136\u5C31\u662F\u540C\u4E00\u754C\u9762\u5728\u4E0D\u540C\u56FD\u5BB6\u7684\u5F62\u5F0F\u4E86\u3002</p><p>\u6574\u4E2A\u62A5\u544A\u53EF\u4EE5\u7528\u952E\u76D8\u4E0A\u4E0B\u5DE6\u53F3\u4F9D\u6B21\u79FB\u52A8\u3002\u53EF\u60F3\u800C\u77E5\uFF0C\u8FD9\u6837\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u8BBE\u8BA1\u4E00\u5B9A\u53EF\u4EE5\u5927\u5E45\u63D0\u9AD8 LQA \u7684\u6548\u7387\u3002</p><p>\u540C\u65F6\uFF0C\u7531\u4E8E\u8FD9\u4E2A GUI \u6D4B\u8BD5\u62A5\u544A\u662F\u57FA\u4E8E Web \u5C55\u73B0\u7684\uFF0C\u6240\u4EE5\u6211\u4EEC\u53EF\u4EE5\u5728\u6D4B\u8BD5\u62A5\u544A\u4E2D\u76F4\u63A5\u63D0\u4F9B\u9012\u4EA4\u7F3A\u9677\u7684\u6309\u94AE\uFF0C\u4E00\u65E6\u53D1\u73B0\u95EE\u9898\u76F4\u63A5\u9012\u4EA4\u7F3A\u9677\uFF0C\u540C\u65F6\u8FD8\u53EF\u4EE5\u628A\u76F8\u5173\u622A\u56FE\u4E00\u8D77\u76F4\u63A5\u9012\u4EA4\u5230\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\uFF0C\u8FD9\u5C06\u66F4\u5927\u7A0B\u5EA6\u5730\u63D0\u9AD8\u6574\u4F53\u6548\u7387\u3002</p><p>\u90A3\u4E48\uFF0C\u600E\u4E48\u624D\u80FD\u5728\u6280\u672F\u4E0A\u5B9E\u73B0\u6D4B\u8BD5\u62A5\u544A\u548C\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\u7684\u4EA4\u4E92\u5462\uFF1F\u5176\u5B9E\uFF0C\u73B0\u4ECA\u7684\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\u5F80\u5F80\u90FD\u6709\u5BF9\u5916\u66B4\u9732 API \u63A5\u53E3\uFF0C\u6211\u4EEC\u5B8C\u5168\u53EF\u4EE5\u5229\u7528\u8FD9\u4E9B API \u63A5\u53E3\u6765\u5B9E\u73B0\u81EA\u5DF1\u7684\u7F3A\u9677\u9012\u4EA4\u903B\u8F91\u3002</p><p>\u8FD9\u79CD\u6D4B\u8BD5\u62A5\u544A\u7684\u5F62\u5F0F\u5C31\u662F eBay \u5728\u5168\u7403\u5316\u7AD9\u70B9\u6D4B\u8BD5\u4E2D\u91C7\u7528\u7684\u65B9\u6848\uFF0C\u76EE\u524D\u5DF2\u7ECF\u53D6\u5F97\u4E86\u5F88\u597D\u5730\u6548\u679C\uFF0C\u964D\u4F4E\u4E86\u5DE5\u4F5C\u91CF\u7684\u540C\u65F6\uFF0C\u8FD8\u5927\u5E45\u5EA6\u63D0\u9AD8\u4E86\u5168\u7403\u5316\u6D4B\u8BD5\u7684\u8D28\u91CF\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u597D\u4E86\uFF0C\u5E0C\u671B\u4E0A\u9762\u7684\u6D4B\u8BD5\u62A5\u544A\u8BBE\u8BA1\u65B9\u6CD5\u53EF\u4EE5\u8BA9\u4F60\u6709\u773C\u524D\u4E00\u4EAE\u7684\u611F\u89C9\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u603B\u7ED3\u4E00\u4E0B\u4ECA\u5929\u7684\u4E3B\u8981\u77E5\u8BC6\u70B9\u3002</p><p>\u65E9\u671F\u57FA\u4E8E\u89C6\u9891\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u7531\u4E8E\u4F53\u79EF\u8F83\u5927\uFF0C\u800C\u4E14\u4E0D\u80FD\u6BD4\u8F83\u65B9\u4FBF\u5730\u548C\u65E5\u5FD7\u9002\u914D\uFF0C\u6240\u4EE5\u5E76\u4E0D\u662F\u6700\u597D\u7684\u89E3\u51B3\u65B9\u6848\u3002\u7406\u60F3\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u5E94\u8BE5\u662F\u7531\u4E00\u7CFB\u5217\u6309\u65F6\u95F4\u987A\u5E8F\u7684\u5C4F\u5E55\u622A\u56FE\u7EC4\u6210\uFF0C\u5E76\u4E14\u53EF\u4EE5\u5728\u8FD9\u4E9B\u622A\u56FE\u4E0A\u9AD8\u4EAE\u4F60\u6240\u64CD\u4F5C\u7684\u5143\u7D20\uFF0C\u540C\u65F6\u6309\u7167\u6267\u884C\u65F6\u5E8F\u914D\u6709\u76F8\u5173\u64CD\u4F5C\u6B65\u9AA4\u7684\u8BE6\u7EC6\u63CF\u8FF0\u3002</p><p>\u5546\u4E1A GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u5DF2\u7ECF\u505A\u5F97\u975E\u5E38\u6210\u719F\uFF0C\u901A\u5E38\u4E0D\u9700\u8981\u505A\u989D\u5916\u7684\u5B9A\u5236\u6216\u8005\u5F00\u53D1\u3002\u4F46\u662F\u5F00\u6E90 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684 GUI \u6D4B\u8BD5\u62A5\u544A\u5F80\u5F80\u9700\u8981\u81EA\u5DF1\u6765\u5F00\u53D1\uFF0C\u4E3B\u8981\u4F7F\u7528\u4E86\u6269\u5C55 Selenium \u539F\u672C\u7684\u64CD\u4F5C\u51FD\u6570\u7684\u65B9\u5F0F\u4EE5\u53CA Hook \u51FD\u6570\u6765\u5B9E\u73B0\u3002</p><p>\u6700\u540E\uFF0C\u6211\u4ECB\u7ECD\u4E86 eBay \u9762\u5BF9\u5168\u7403\u5316\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D GUI \u6D4B\u8BD5\u62A5\u544A\u7684\u521B\u65B0\u8BBE\u8BA1\uFF0C\u5E0C\u671B\u4F60\u4E5F\u53EF\u4EE5\u501F\u9274\u8FD9\u79CD\u65B9\u6CD5\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5982\u679C\u81EA\u5DF1\u53BB\u5F00\u53D1 GUI \u6D4B\u8BD5\u62A5\u544A\u7684\u529F\u80FD\uFF0C\u4F60\u8FD8\u80FD\u60F3\u5230\u5176\u4ED6\u66F4\u591A\u5B9E\u7528\u7684\u529F\u80FD\u5417\uFF1F\u4F60\u53C8\u662F\u5982\u4F55\u5B9E\u73B0\u8FD9\u4E9B\u529F\u80FD\u7684\uFF1F</p>',54);function i(t,s){return r}var a=p(o,[["render",i],["__file","18.html.vue"]]);export{a as default};
